export function Pagination<NodesType>({
  connection,
  children = () => {
    console.warn('<Pagination> requires children to work properly');
    return null;
  },
  namespace = '',
}: PaginationProps<NodesType>): ReturnType<FC> {
  const [isLoading, setIsLoading] = useState(false);
  const transition = useNavigation();
  const location = useLocation();
  const navigate = useNavigate();

  // Reset loading state once the transition state is idle
  useEffect(() => {
    if (transition.state === 'idle') {
      setIsLoading(false);
    }
  }, [transition.state]);

  const {
    endCursor,
    hasNextPage,
    hasPreviousPage,
    nextPageUrl,
    nodes,
    previousPageUrl,
    startCursor,
  } = usePagination<NodesType>(connection, namespace);

  const state = useMemo(
    () => ({
      ...location.state,
      pagination: {
        ...(location.state?.pagination || {}),
        [namespace]: {
          pageInfo: {
            endCursor,
            hasPreviousPage,
            hasNextPage,
            startCursor,
          },
          nodes,
        },
      },
    }),
    [
      endCursor,
      hasNextPage,
      hasPreviousPage,
      startCursor,
      nodes,
      namespace,
      location.state,
    ],
  );

  const NextLink = useMemo(
    () =>
      forwardRef<HTMLAnchorElement, Omit<LinkProps, 'to'>>(
        function NextLink(props, ref) {
          return hasNextPage
            ? createElement(Link, {
                preventScrollReset: true,
                ...props,
                to: nextPageUrl,
                state,
                replace: true,
                ref,
                onClick: () => setIsLoading(true),
              })
            : null;
        },
      ),
    [hasNextPage, nextPageUrl, state],
  );

  const PreviousLink = useMemo(
    () =>
      forwardRef<HTMLAnchorElement, Omit<LinkProps, 'to'>>(
        function PrevLink(props, ref) {
          return hasPreviousPage
            ? createElement(Link, {
                preventScrollReset: true,
                ...props,
                to: previousPageUrl,
                state,
                replace: true,
                ref,
                onClick: () => setIsLoading(true),
              })
            : null;
        },
      ),
    [hasPreviousPage, previousPageUrl, state],
  );

  return children({
    state,
    hasNextPage,
    hasPreviousPage,
    isLoading,
    nextPageUrl,
    nodes,
    previousPageUrl,
    NextLink,
    PreviousLink,
  });
}

